  ('disabled-c5fb3965-moex-00331', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '衛生主管機關公開警告特定傳染病可能大流行，呼籲民眾於公共場所應戴 口罩。關於該公開警告，下列敘述何者正確？', '["具有意思表示性質，為對人之一般處分", "已侵害人民之基本權利，應有法令依據", "主管機關之行為不以發生法律效果為目的", "人民如不服公開警告，得提起訴願及撤銷訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00332', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政罰法之規定，一行為同時觸犯刑事法律及違反行政法上義務規定 時，下列敘述何者正確？', '["行政機關無須將涉及刑事部分移送該管司法機關，即可逕行裁處行政罰", "刑事部分若經檢察官為緩起訴處分確定者，行政機關得依違反行政法上 義務規定裁處之", "刑事部分若經刑事法院判決無罪確定，行政罰裁處權時效應自違反行政 法上義務之行為終了時起算", "對於得沒入之物，縱使已經刑事法院宣告沒收，行政機關仍可裁處沒入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00333', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '有關行政罰之行為數認定，下列敘述何者錯誤？', '["對連續託播藥物廣告之處罰，按廣告播放次數作為行為數認定標準", "填具一張進口報單同時逃漏進口稅、貨物稅及營業稅，應分別處罰", "道路交通管理處罰條例對持續違規停車予多次處罰，不違反一事不二罰 原則", "納稅義務人違反作為義務而被處行為罰，僅須其有違反作為義務之行為 即應受處罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00334', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政罰法之規定，行政機關對於易生危險之扣留物，可如何處理？', '["應立即發還", "即行拍賣", "得予變賣", "得予毀棄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00335', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依社會秩序維護法規定，罰鍰應於裁處確定之翌日起 10 日內完納，被處 罰人如逾期不完納時，應如何處置？', '["由警察機關聲請地方法院簡易庭裁定易以拘留", "由地方法院簡易庭聲請同法院普通庭裁定易以拘留", "由警察機關移送行政執行分署執行", "由警察機關移送地方法院民事執行處執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00336', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '依行政執行法所為之拘提、管收，下列敘述何者正確？', '["拘提由行政執行官逕行裁定", "行政執行分署不服法院關於拘提之裁定，得提起抗告", "管收期限最長不得逾2個月", "義務人之公法上金錢給付義務因管收期滿而免除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00337', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '下列何種義務逾期不履行時，得移送該管行政執行分署執行之？', '["人民依採購契約所承擔之金錢給付義務", "命人民不得參與未經核准之集會遊行", "人民未依規定清除廢棄物，命其限期清除", "人民遭行政機關裁處罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00338', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '行政程序之代理人，有二人以上者，關於其代理，下列敘述何者正確？', '["均不得單獨代理當事人", "得分別授權代理特定程序行為", "須補正後，得單獨代理當事人", "均得單獨代理當事人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00339', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '有關公示送達之敘述，下列何者正確？', '["應為送達之處所不明時，行政機關不得依職權命為公示送達", "公示送達應由行政機關將文書或其節本刊登於政府公報或新聞紙", "於有治外法權人之住居所或事務所為送達無效者，行政機關得依申請， 准為公示送達", "公示送達應由行政機關保管送達之文書，得於行政機關公告欄黏貼公 告，告知應受送達人隨時領取之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00340', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '原處分機關對於甲申請行政程序再開不作為，甲提起訴願。於訴願程序中， 原處分機關作成否准程序再開之處分，下列敘述何者正確？', '["受理訴願機關應駁回甲之訴願", "受理訴願機關應不受理甲之訴願", "若甲並無特別表示，受理訴願機關應續行甲之訴願程序", "受理訴願機關應通知訴願人逕行向行政法院起訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
